// Calculate weekly social media stats
const posts = $input.all().map(item => item.json);

const totalPublished = posts.length;

// Count by pillar
const byPillar = {};
for (const p of posts) {
  const pillar = p.pillar || 'unknown';
  byPillar[pillar] = (byPillar[pillar] || 0) + 1;
}

// Count by platform (platforms may be array or comma-separated string)
const byPlatform = {};
for (const p of posts) {
  let platforms = p.platforms || [];
  if (typeof platforms === 'string') {
    platforms = platforms.split(',').map(s => s.trim());
  }
  // ALWAYS exclude facebook
  platforms = platforms.filter(pl => pl !== 'facebook' && pl !== 'fb');
  for (const pl of platforms) {
    byPlatform[pl] = (byPlatform[pl] || 0) + 1;
  }
}

// Count by post_type
const byType = {};
for (const p of posts) {
  const t = p.post_type || 'unknown';
  byType[t] = (byType[t] || 0) + 1;
}

// Build pillar breakdown text
let pillarLines = '';
for (const [pillar, count] of Object.entries(byPillar)) {
  pillarLines += `  - ${pillar}: ${count}\n`;
}

// Build platform breakdown text
let platformLines = '';
for (const [platform, count] of Object.entries(byPlatform)) {
  platformLines += `  - ${platform}: ${count}\n`;
}

// Build type breakdown text
let typeLines = '';
for (const [type, count] of Object.entries(byType)) {
  typeLines += `  - ${type}: ${count}\n`;
}

const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric' });
const weekEnd = new Date().toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric' });

const report = `Weekly Social Media Report (${weekStart} - ${weekEnd})\n\nTotal Published: ${totalPublished}\n\nBy Pillar:\n${pillarLines}\nBy Platform:\n${platformLines}\nBy Type:\n${typeLines}`;

return [{ json: {
  report,
  total_published: totalPublished,
  by_pillar: byPillar,
  by_platform: byPlatform,
  by_type: byType
}}];
